class Ljusstake():

  def __init__(self, ljus, batteri = False):
    self.antal_ljus = ljus
    self.batteridriven = batteri

  def __str__(self):
    sträng = "Har "+ str(self.antal_ljus) + " ljus "
    if self.batteridriven == True:
      sträng += "och går på batteri."
    else:
      sträng += "och går på el."
    return sträng

  def __lt__(self, other):
    if self.antal_ljus < other.antal_ljus:
      return True
    else:
      return False

  def fixa_batteri(self):
    self.batteridriven = True

def läsa_in_från_fil(filnamn):
  try:
    fil = open(filnamn, "r")
    rad = fil.readline().strip()
  except FileNotFoundError:
    print("Ingen fil med namn \"" + filnamn + "\" hittades.")
    rad = ""
  ljus_lista = []
  while rad != "":           #Så länge som raden inte är tom
    rad = rad.split()        #delar upp strängen i två
    if rad[1] == "False":
      ljus = Ljusstake(int(rad[0]), False)
    else:
      ljus = Ljusstake(int(rad[0]), True)
    ljus_lista.append(ljus)
    rad = fil.readline().strip()  #läser in nästa rad
  return ljus_lista

def hitta(ljusstakar):
  antal = int(input("Hur många ljus har ljusstaken du letar efter? "))
  for ljusstake in ljusstakar:
    if ljusstake.antal_ljus == antal:
      print("Ljusstake hittad")
      return ljusstake
  print("Hittades inte!")
  return False

def main():	
  mina_ljusstakar = läsa_in_från_fil("ljus.txt")
  mina_ljusstakar.sort()
  for i in range(len(mina_ljusstakar)):
    print(str(i+1) + ". " + str(mina_ljusstakar[i]))

  ljus = hitta(mina_ljusstakar)
  if ljus != False:
    ljus.fixa_batteri()

  for i in range(len(mina_ljusstakar)):
    print(str(i+1) + ". " + str(mina_ljusstakar[i]))


main()
